body {
background-color: #F8F9FB;
-ms-text-size-adjust: 100%;
-webkit-text-size-adjust: none;
width: 100% !important;
height: 100%;
line-height: 1.6;
}

.body-wrap {
width: 100% !important;
background-color: #F8F9FB;
padding-bottom: 5px !important;
}

.body-wrap a {
color: #006aff;
text-decoration: none;
}

.active-btn, .active-btn:hover, .active-btn:visited {
display: inline-block;
color: #FFFFFF !important;
background-color: #006aff;
border-radius: 5px;
box-sizing: border-box;
text-decoration: none;
font-size: 12px;
font-weight: bold;
padding: 8px !important;
border: 1px solid;
line-height: 20px !important;
}
.active-btn:first-letter{
text-transform: uppercase;
}
.active-btn-text {
text-decoration: none;
margin: 8px !important;
color: #FFFFFF;
}

.footer-wrap {
width: 100%;
padding: 0 !important;
font-size: 12px;
background-color: #F8F9FB;
}

.footer-wrap .container {
max-width: 640px !important;
}

.footer-wrap .container .mobile-apps-links {
margin-top: 20px !important;
}

.footer-wrap .content {
max-width: 640px !important;
}

.footer-wrap a {
text-decoration: none;
color: #1F1F1F !important;
}

.footer--social-icon {
margin-right: 10px !important;
}

.powered-by-uscreen {
text-align: right;
vertical-align: middle;
}

.powered-by-uscreen a span {
vertical-align: middle;
}

.powered-by-uscreen a {
vertical-align: top;
display: inline-block;
}

.copyrate {
text-align: left;
vertical-align: middle;
}

